mapper.select:
SELECT CAT_SEQ, FAMILY_ID, CAT_NM, SORT_ORDER, USE_YN, REG_ID, REG_DT, UPD_ID, UPD_DT
FROM LIVING_BUDGET_CAT
WHERE FAMILY_ID = #{familyId}
  AND CAT_SEQ = #{catSeq}

SELECT i.ITEM_SEQ, i.FAMILY_ID, i.CAT_SEQ, c.CAT_NM, i.ITEM_NM, i.BUDGET_AMT, i.INCOME_PLAN_SEQ, p.PLAN_NM AS INCOME_PLAN_NM, i.CC_SEQ, cc.CC_NM, i.SORT_ORDER, i.USE_YN, i.DEL_YN, i.MEMO, i.REG_ID, i.REG_DT, i.UPD_ID, i.UPD_DT FROM LIVING_BUDGET_ITEM i JOIN LIVING_BUDGET_CAT c ON c.CAT_SEQ = i.CAT_SEQ LEFT JOIN CASH_FLOW_PLAN_MST p ON p.PLAN_SEQ = i.INCOME_PLAN_SEQ LEFT JOIN COST_CENTER_MST cc ON cc.CC_SEQ = i.CC_SEQ WHERE i.FAMILY_ID = #{familyId} AND i.DEL_YN = 'N'
AND i.CAT_SEQ = #{catSeq}
ORDER BY i.SORT_ORDER, i.ITEM_SEQ

mapper.update:
UPDATE LIVING_BUDGET_ITEM
SET DEL_YN = 'Y',
    UPD_ID = #{updId},
    UPD_DT = NOW()
WHERE FAMILY_ID = #{familyId}
  AND ITEM_SEQ  = #{itemSeq}

mapper.select:
SELECT EXP_SEQ, FAMILY_ID, EXP_YYMM, MEMO,
       REG_ID, REG_DT, UPD_ID, UPD_DT,
       0 AS TOTAL_BUDGET_AMT, 0 AS TOTAL_ACTUAL_AMT
FROM LIVING_EXPENSE_MST
WHERE FAMILY_ID = #{familyId}
  AND EXP_YYMM  = #{expYymm}

mapper.update:
DELETE FROM LIVING_INCOME_MST
WHERE FAMILY_ID = #{familyId}
  AND INCOME_SEQ = #{incomeSeq}
